ControlPropertyState.AutoRuleBindingString:
Set(varBarcodeData, 
    With(
        {
            BC: BarcodeScannerRegistration_1.Value
        },
        {
            ItemID: Mid(BC, 3, 14),
            Expiration: Mid(BC, 19, 6),
            Batch: Mid(BC, 27, Len(BC) - 26),
            ExpirationFormatted: Date(
                2000 + Value(Mid(BC, 19, 2)),
                Value(Mid(BC, 21, 2)),
                Value(Mid(BC, 23, 2))
            )
        }
    )
);

Remove(GTIN_Lookups, selectedRecord);
If(
    IsEmpty(Errors(GTIN_Lookups, selectedRecord)),
    UpdateContext({
        CurrentItem: First(Table1_3.SelectedItems),
        isItemSelected: false,
        newMode: false,
        deleteMode: false
    });
    Notify("✓ Item deleted successfully", NotificationType.Success, 3000),
    Notify("❌ Failed to delete item: " & First(Errors(GTIN_Lookups, selectedRecord)).Message, NotificationType.Error, 5000)
)

SubmitForm(Form1_3);
// Check if we came from QuickPick
If(!IsBlank(ctxRegBarcode),
   // Return to QuickPick with the registered product
   Set(varReturnToQuickPick, true);
   Navigate(QuickPick, ScreenTransition.None);
   Notify("Product registered! Now add it to inventory", NotificationType.Success, 3000)
)
